import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { gamesAPI } from '../services/api';

interface Game {
  _id: string;
  title: string;
  description: string;
  price: number;
  platform: string;
  region: string;
  images: string[];
  availability: string;
}

const Home: React.FC = () => {
  const [games, setGames] = useState<Game[]>([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    platform: '',
    region: ''
  });

  useEffect(() => {
    fetchGames();
  }, [filters]);

  const fetchGames = async () => {
    try {
      const response = await gamesAPI.getGames(filters);
      setGames(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching games:', error);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8">Alpha Store - حسابات الألعاب</h1>

        <div className="bg-white p-6 rounded-lg shadow mb-8">
          <h2 className="text-lg font-semibold mb-4">بحث وتصفية</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">المنصة</label>
              <select
                value={filters.platform}
                onChange={(e) => setFilters({...filters, platform: e.target.value})}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
              >
                <option value="">كل المنصات</option>
                <option value="PC">PC</option>
                <option value="PlayStation">PlayStation</option>
                <option value="Xbox">Xbox</option>
                <option value="Nintendo Switch">Nintendo Switch</option>
                <option value="Mobile">موبايل</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">المنطقة</label>
              <select
                value={filters.region}
                onChange={(e) => setFilters({...filters, region: e.target.value})}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
              >
                <option value="">كل المناطق</option>
                <option value="Global">عالمي</option>
                <option value="North America">أمريكا الشمالية</option>
                <option value="Europe">أوروبا</option>
                <option value="Asia">آسيا</option>
                <option value="Middle East">الشرق الأوسط</option>
              </select>
            </div>
          </div>
        </div>

        {loading ? (
          <div className="text-center py-8">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto"></div>
            <p className="mt-4 text-gray-600">جاري التحميل...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {games.map((game) => (
              <div key={game._id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow">
                {game.images && game.images.length > 0 && (
                  <img
                    src={`http://localhost:5000${game.images[0]}`}
                    alt={game.title}
                    className="w-full h-48 object-cover"
                  />
                )}
                <div className="p-4">
                  <h3 className="text-lg font-semibold text-gray-900 mb-2">{game.title}</h3>
                  <p className="text-gray-600 text-sm mb-3 line-clamp-2">{game.description}</p>
                  <div className="flex justify-between items-center mb-3">
                    <span className="text-2xl font-bold text-indigo-600">${game.price}</span>
                    <span className={`px-2 py-1 text-xs rounded-full ${
                      game.availability === 'available' ? 'bg-green-100 text-green-800' :
                      game.availability === 'sold' ? 'bg-red-100 text-red-800' :
                      'bg-yellow-100 text-yellow-800'
                    }`}>
                      {game.availability === 'available' ? 'متاح' :
                       game.availability === 'sold' ? 'تم البيع' : 'محجوز'}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm text-gray-500 mb-3">
                    <span>{game.platform}</span>
                    <span>{game.region}</span>
                  </div>
                  <Link
                    to={`/game/${game._id}`}
                    className="w-full bg-indigo-600 text-white py-2 px-4 rounded-md hover:bg-indigo-700 transition-colors text-center block"
                  >
                    عرض التفاصيل
                  </Link>
                </div>
              </div>
            ))}
          </div>
        )}

        {!loading && games.length === 0 && (
          <div className="text-center py-8">
            <p className="text-gray-600 text-lg">لا توجد حسابات متاحة حالياً</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Home;
